const hamburger=document.querySelector(".hamburger");const menu=document.querySelector(".menu");const menuList=document.querySelector(".menu ul");const menuLinks=document.querySelectorAll(".menu ul li a");hamburger.addEventListener("click",(e)=>{e.stopPropagation();menu.classList.toggle("active")});menuLinks.forEach(link=>{link.addEventListener("click",()=>{menu.classList.remove("active")})});document.addEventListener("click",(e)=>{if(!menu.contains(e.target)){menu.classList.remove("active")}})